<!-- Long component name: a wide inline component drops to its own line and the
     preceding word stays hugged on the text line (it is not stranded). Pins that
     the boundary break is independent of tag-name length. -->
<p>
	text1 text2 text3 text4 text5 text6 text7 text8 text9 text10 text11 text12 aaaaaaaaaaaaaa and <VeryLongComponentName href="aaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaa">content</VeryLongComponentName> tail1 tail2 tail3 tail4 tail5 tail6
</p>
